import hashlib
import json
import time
from typing import Optional, Dict, Any
from datetime import datetime, timedelta
import numpy as np

class CacheEntry:
    """Cache entry with metadata"""
    def __init__(self, response: str, timestamp: float, ttl: int = 3600):
        self.response = response
        self.timestamp = timestamp
        self.ttl = ttl
        self.hits = 0

    def is_expired(self) -> bool:
        return time.time() - self.timestamp > self.ttl

    def record_hit(self):
        self.hits += 1

class ExactMatchCache:
    """Simple exact-match cache"""
    def __init__(self, max_size: int = 1000):
        self.cache: Dict[str, CacheEntry] = {}
        self.max_size = max_size

    def _get_key(self, prompt: str, model: str, **kwargs) -> str:
        """Generate cache key from prompt and parameters"""
        key_data = {"prompt": prompt, "model": model, **kwargs}
        key_str = json.dumps(key_data, sort_keys=True)
        return hashlib.md5(key_str.encode()).hexdigest()

    def get(self, prompt: str, model: str = "gpt-3.5-turbo", **kwargs) -> Optional[str]:
        key = self._get_key(prompt, model, **kwargs)
        if key in self.cache:
            entry = self.cache[key]
            if not entry.is_expired():
                entry.record_hit()
                return entry.response
            else:
                del self.cache[key]
        return None

    def set(self, prompt: str, response: str, model: str = "gpt-3.5-turbo", **kwargs):
        key = self._get_key(prompt, model, **kwargs)
        if len(self.cache) >= self.max_size:
            # Remove least recently used
            oldest_key = min(self.cache.keys(), key=lambda k: self.cache[k].timestamp)
            del self.cache[oldest_key]
        self.cache[key] = CacheEntry(response, time.time())

    def stats(self) -> Dict:
        total_hits = sum(e.hits for e in self.cache.values())
        return {"size": len(self.cache), "total_hits": total_hits}

class SemanticCache:
    """Cache based on semantic similarity using embeddings"""
    def __init__(self, similarity_threshold: float = 0.9):
        self.cache: list = []  # List of (embedding, response, metadata)
        self.threshold = similarity_threshold

    def _get_embedding(self, text: str) -> np.ndarray:
        """Simulate embedding generation - use real embeddings in production"""
        # Simplified: use text hash as pseudo-embedding
        return np.array([ord(c) for c in text[:100]])

    def _cosine_similarity(self, emb1: np.ndarray, emb2: np.ndarray) -> float:
        return np.dot(emb1, emb2) / (np.linalg.norm(emb1) * np.linalg.norm(emb2))

    def get(self, prompt: str) -> Optional[str]:
        prompt_emb = self._get_embedding(prompt)
        for emb, response, timestamp in self.cache:
            if time.time() - timestamp > 3600:  # TTL 1 hour
                continue
            similarity = self._cosine_similarity(prompt_emb, emb)
            if similarity >= self.threshold:
                return response
        return None

    def set(self, prompt: str, response: str):
        emb = self._get_embedding(prompt)
        self.cache.append((emb, response, time.time()))
        # Keep only recent 1000 entries
        if len(self.cache) > 1000:
            self.cache = self.cache[-1000:]

