import numpy as np
from typing import Dict, List, Tuple
import re

class ModelRouter:
    """Intelligent model selection based on query"""

    def __init__(self):
        self.models = {
            "fast": {
                "name": "gpt-3.5-turbo",
                "cost_per_1k": 0.001,
                "latency_ms": 500,
                "max_tokens": 4096
            },
            "balanced": {
                "name": "claude-3-haiku",
                "cost_per_1k": 0.00025,
                "latency_ms": 800,
                "max_tokens": 8192
            },
            "premium": {
                "name": "gpt-4-turbo",
                "cost_per_1k": 0.01,
                "latency_ms": 1500,
                "max_tokens": 128000
            }
        }

    def classify_complexity(self, query: str) -> str:
        """Classify query complexity"""
        # Complexity indicators
        complex_indicators = [
            "explain", "analyze", "compare", "contrast", "evaluate",
            "synthesize", "reason", "calculate", "derive", "prove"
        ]

        medium_indicators = [
            "describe", "summarize", "list", "what is", "how to",
            "tell me about", "explain briefly"
        ]

        query_lower = query.lower()
        words = len(query.split())

        # Long queries are often more complex
        if words > 100:
            return "premium"

        for indicator in complex_indicators:
            if indicator in query_lower:
                return "premium"

        for indicator in medium_indicators:
            if indicator in query_lower:
                return "balanced"

        return "fast"

    def route(self, query: str, budget: float = None, max_latency: float = None) -> Dict:
        """Route query to appropriate model"""
        complexity = self.classify_complexity(query)

        # Start with complexity-based selection
        if complexity == "premium":
            selected = self.models["premium"]
        elif complexity == "balanced":
            selected = self.models["balanced"]
        else:
            selected = self.models["fast"]

        # Apply constraints
        if budget and selected["cost_per_1k"] > budget:
            # Downgrade to cheaper model
            for model in ["fast", "balanced"]:
                if self.models[model]["cost_per_1k"] <= budget:
                    selected = self.models[model]
                    break

        if max_latency and selected["latency_ms"] > max_latency:
            # Need faster model
            for model in ["fast", "balanced"]:
                if self.models[model]["latency_ms"] <= max_latency:
                    selected = self.models[model]
                    break

        return {
            "model": selected["name"],
            "complexity": complexity,
            "estimated_cost": selected["cost_per_1k"],
            "estimated_latency": selected["latency_ms"]
        }

class SemanticRouter:
    """Router using embeddings for classification"""

    def __init__(self):
        self.routes = {
            "math": ["calculate", "solve", "equation", "sum", "difference"],
            "code": ["function", "class", "import", "def", "return", "error"],
            "creative": ["write", "poem", "story", "essay", "creative"],
            "factual": ["what", "when", "where", "who", "fact", "history"]
        }

    def route(self, query: str) -> str:
        """Route based on semantic category"""
        query_lower = query.lower()
        scores = {}

        for category, keywords in self.routes.items():
            score = sum(1 for kw in keywords if kw in query_lower)
            scores[category] = score

        best_category = max(scores, key=scores.get) if scores else "factual"

        # Map category to model
        category_map = {
            "math": "gpt-4-turbo",
            "code": "gpt-4-turbo",
            "creative": "claude-3-sonnet",
            "factual": "gpt-3.5-turbo"
        }

        return category_map.get(best_category, "gpt-3.5-turbo")

class CostAwareRouter:
    """Router that optimizes for cost"""

    def __init__(self, daily_budget: float = 10.0):
        self.daily_budget = daily_budget
        self.daily_spent = 0.0

    def route(self, query: str) -> str:
        """Route based on remaining budget"""
        remaining = self.daily_budget - self.daily_spent

        if remaining < 1.0:
            # Budget tight, use cheap model
            return "gpt-3.5-turbo"
        elif remaining < 5.0:
            # Moderate budget
            return "claude-3-haiku"
        else:
            # Plenty of budget
            return "gpt-4-turbo"

    def record_cost(self, cost: float):
        self.daily_spent += cost

