import numpy as np

class SemanticCache:
    def __init__(self, threshold=0.90):
        self.threshold = threshold
        self.cache = []  # Stores tuples of (query_vector, cached_llm_response)

    def _cosine_similarity(self, v1, v2):
        return np.dot(v1, v2) / (np.linalg.norm(v1) * np.linalg.norm(v2))

    def check_cache(self, query_vector):
        for cached_vector, cached_response in self.cache:
            if self._cosine_similarity(query_vector, cached_vector) >= self.threshold:
                return cached_response
        return None

    def store(self, query_vector, response):
        self.cache.append((query_vector, response))

